  1→//! WASM bindings for Falcon-512 signature scheme.
  2→//!
  3→//! This module provides JavaScript-friendly bindings for browser use.
  4→//! Currently uses SHAKE256 hash; Poseidon support will be added for Starknet.
  5→
  6→#![cfg(feature = "wasm")]
  7→
  8→use wasm_bindgen::prelude::*;
  9→
 10→use crate::falcon::{Falcon, SecretKey, Signature, VerifyingKey, PUBLIC_KEY_LEN};
 11→use crate::hash_to_point::Shake256Hash;
 12→use crate::SALT_LEN;
 13→
 14→/// Generate a new Falcon-512 keypair.
 15→///
 16→/// Returns a JavaScript object with `sk` (secret key bytes) and `vk` (verifying key bytes).
 17→///
 18→/// Note: Key generation is slow (~1-2 minutes) due to NTRU complexity.
 19→#[wasm_bindgen]
 20→pub fn keygen(seed: &[u8]) -> Result<JsValue, JsError> {
 21→    if seed.len() < 32 {
 22→        return Err(JsError::new("Seed must be at least 32 bytes"));
 23→    }
 24→
 25→    let (sk, vk) = Falcon::<Shake256Hash>::keygen_with_seed(seed);
 26→
 27→    let result = js_sys::Object::new();
 28→    js_sys::Reflect::set(
 29→        &result,
 30→        &"sk".into(),
 31→        &js_sys::Uint8Array::from(&sk.to_bytes()[..]),
 32→    )
 33→    .map_err(|e| JsError::new(&format!("Failed to set sk: {:?}", e)))?;
 34→    js_sys::Reflect::set(
 35→        &result,
 36→        &"vk".into(),
 37→        &js_sys::Uint8Array::from(&vk.to_bytes()[..]),
 38→    )
 39→    .map_err(|e| JsError::new(&format!("Failed to set vk: {:?}", e)))?;
 40→
 41→    Ok(result.into())
 42→}
 43→
 44→/// Sign a message with a secret key.
 45→///
 46→/// Parameters:
 47→/// - `sk_bytes`: The secret key bytes (serialized as 4 × 896 = 3584 bytes via `SecretKey::to_bytes`)
 48→/// - `message`: The message to sign
 49→/// - `salt`: A 40-byte random salt (must be exactly `SALT_LEN` bytes)
 50→///
 51→/// Returns a JavaScript object with:
 52→/// - `signature`: `Uint8Array` of 666 bytes (the full Falcon-512 signature)
 53→/// - `salt`: `Uint8Array` of 40 bytes (echo of the provided salt)
 54→///
 55→/// # Notes
 56→///
 57→/// The caller is responsible for generating a cryptographically random `salt` before
 58→/// calling this function. The same salt must not be reused for different messages.
 59→#[wasm_bindgen]
 60→pub fn sign(sk_bytes: &[u8], message: &[u8], salt: &[u8]) -> Result<JsValue, JsError> {
 61→    // Validate salt length
 62→    if salt.len() != SALT_LEN {
 63→        return Err(JsError::new(&format!(
 64→            "Invalid salt length: expected {SALT_LEN}, got {}",
 65→            salt.len()
 66→        )));
 67→    }
 68→    let salt_arr: [u8; SALT_LEN] = salt
 69→        .try_into()
 70→        .map_err(|_| JsError::new("Failed to convert salt to fixed-size array"))?;
 71→
 72→    // Deserialize the secret key (reconstructs b0_fft and LDL tree)
 73→    let sk = SecretKey::from_bytes(sk_bytes).map_err(|e| JsError::new(&e.to_string()))?;
 74→
 75→    // Sign the message with the provided salt
 76→    let sig = Falcon::<Shake256Hash>::sign_with_salt(&sk, message, &salt_arr);
 77→
 78→    // Build return object: { signature: Uint8Array, salt: Uint8Array }
 79→    let result = js_sys::Object::new();
 80→
 81→    js_sys::Reflect::set(
 82→        &result,
 83→        &"signature".into(),
 84→        &js_sys::Uint8Array::from(&sig.to_bytes()[..]),
 85→    )
 86→    .map_err(|e| JsError::new(&format!("Failed to set signature: {e:?}")))?;
 87→
 88→    js_sys::Reflect::set(
 89→        &result,
 90→        &"salt".into(),
 91→        &js_sys::Uint8Array::from(sig.salt().as_slice()),
 92→    )
 93→    .map_err(|e| JsError::new(&format!("Failed to set salt: {e:?}")))?;
 94→
 95→    Ok(result.into())
 96→}
 97→
 98→/// Verify a signature.
 99→///
100→/// Parameters:
101→/// - `vk_bytes`: The verifying key (public key) bytes
102→/// - `message`: The signed message
103→/// - `signature`: The signature bytes
104→///
105→/// Returns true if the signature is valid, false otherwise.
106→#[wasm_bindgen]
107→pub fn verify(vk_bytes: &[u8], message: &[u8], signature: &[u8]) -> Result<bool, JsError> {
108→    if vk_bytes.len() != PUBLIC_KEY_LEN {
109→        return Err(JsError::new(&format!(
110→            "Invalid verifying key length: expected {}, got {}",
111→            PUBLIC_KEY_LEN,
112→            vk_bytes.len()
113→        )));
114→    }
115→
116→    let vk_arr: [u8; PUBLIC_KEY_LEN] = vk_bytes
117→        .try_into()
118→        .map_err(|_| JsError::new("Invalid verifying key"))?;
119→
120→    let vk = VerifyingKey::from_bytes(&vk_arr).map_err(|e| JsError::new(&e.to_string()))?;
121→
122→    let sig = Signature::from_bytes(signature).map_err(|e| JsError::new(&e.to_string()))?;
123→
124→    Falcon::<Shake256Hash>::verify(&vk, message, &sig).map_err(|e| JsError::new(&e.to_string()))
125→}
126→
127→/// Get the public key length in bytes.
128→#[wasm_bindgen]
129→pub fn public_key_length() -> usize {
130→    PUBLIC_KEY_LEN
131→}
132→
133→/// Get the salt length in bytes.
134→#[wasm_bindgen]
135→pub fn salt_length() -> usize {
136→    SALT_LEN
137→}
