139→// ─── wasm-bindgen tests ──────────────────────────────────────────────────────
140→//
141→// Run with: wasm-pack test --node --features wasm
142→// These tests exercise the actual `#[wasm_bindgen]` surface through the
143→// wasm-bindgen-test harness (no browser required when using --node).
144→
145→#[cfg(test)]
146→mod wasm_tests {
147→    use super::*;
148→    use wasm_bindgen_test::wasm_bindgen_test;
149→
150→    // ── constants ───────────────────────────────────────────────────────────
151→
152→    /// `public_key_length()` must return 896.
153→    #[wasm_bindgen_test]
154→    fn wasm_public_key_length_is_896() {
155→        assert_eq!(public_key_length(), 896);
156→    }
157→
158→    /// `salt_length()` must return 40.
159→    #[wasm_bindgen_test]
160→    fn wasm_salt_length_is_40() {
161→        assert_eq!(salt_length(), 40);
162→    }
163→
164→    // ── verify ──────────────────────────────────────────────────────────────
165→
166→    /// `verify()` with wrong pk length returns an error.
167→    #[wasm_bindgen_test]
168→    fn wasm_verify_rejects_short_pk() {
169→        let short_pk = vec![0u8; 10];
170→        let result = verify(&short_pk, b"msg", b"sig");
171→        assert!(result.is_err(), "short pk must be rejected");
172→    }
173→
174→    /// `verify()` with correct pk length but invalid signature is rejected.
175→    #[wasm_bindgen_test]
176→    fn wasm_verify_rejects_invalid_signature() {
177→        let zero_pk = vec![0u8; PUBLIC_KEY_LEN];
178→        let bad_sig = vec![0xFF_u8; 50]; // bad header
179→        let result = verify(&zero_pk, b"msg", &bad_sig);
180→        assert!(result.is_err(), "invalid signature header must be rejected");
181→    }
182→
183→    // ── sign ────────────────────────────────────────────────────────────────
184→
185→    /// `sign()` with invalid sk length (not 4 * PUBLIC_KEY_LEN) must return an error.
186→    #[wasm_bindgen_test]
187→    fn wasm_sign_rejects_invalid_sk_length() {
188→        let short_sk = vec![0u8; 100];
189→        let result = sign(&short_sk, b"hello", &[0u8; SALT_LEN]);
190→        assert!(result.is_err(), "sign() must reject sk with wrong length");
191→    }
192→
193→    /// `sign()` with wrong salt length must return an error.
194→    #[wasm_bindgen_test]
195→    fn wasm_sign_rejects_invalid_salt_length() {
196→        // Use a dummy sk of the right byte length but invalid content
197→        let dummy_sk = vec![0u8; 4 * crate::falcon::PUBLIC_KEY_LEN];
198→        let wrong_salt = vec![0u8; 10]; // too short
199→        let result = sign(&dummy_sk, b"hello", &wrong_salt);
200→        assert!(result.is_err(), "sign() must reject salt with wrong length");
201→    }
202→
203→    /// `sign()` with a valid sk (from keygen) must return a JS object with
204→    /// `signature` (Uint8Array of SIGNATURE_LEN) and `salt` (Uint8Array of SALT_LEN).
205→    ///
206→    /// NOTE: this test requires a real keypair, so it exercises the full keygen → sign path.
207→    /// Key generation is slow; this test is intentionally scoped to a fast deterministic path.
208→    #[wasm_bindgen_test]
209→    fn wasm_sign_succeeds_with_valid_sk() {
210→        use crate::falcon::SIGNATURE_LEN;
211→
212→        let seed = [20u8; 32];
213→        let keypair = keygen(&seed).expect("keygen must succeed with 32-byte seed");
214→
215→        // Extract sk bytes from the keypair JsValue
216→        let sk_js =
217→            js_sys::Reflect::get(&keypair, &"sk".into()).expect("keypair must have sk property");
218→        let sk_arr = js_sys::Uint8Array::from(sk_js);
219→        let sk_bytes = sk_arr.to_vec();
220→
221→        let salt = [0u8; SALT_LEN];
222→        let result = sign(&sk_bytes, b"hello wasm sign", &salt);
223→        assert!(
224→            result.is_ok(),
225→            "sign() must succeed with valid sk: {:?}",
226→            result.err()
227→        );
228→
229→        let result_obj = result.unwrap();
230→
231→        // Must have a `signature` Uint8Array of length SIGNATURE_LEN
232→        let sig_js = js_sys::Reflect::get(&result_obj, &"signature".into())
233→            .expect("result must have `signature` property");
234→        let sig_arr = js_sys::Uint8Array::from(sig_js);
235→        assert_eq!(
236→            sig_arr.length() as usize,
237→            SIGNATURE_LEN,
238→            "signature must be SIGNATURE_LEN={} bytes",
239→            SIGNATURE_LEN
240→        );
241→
242→        // Must have a `salt` Uint8Array of length SALT_LEN
243→        let salt_js = js_sys::Reflect::get(&result_obj, &"salt".into())
244→            .expect("result must have `salt` property");
245→        let salt_arr = js_sys::Uint8Array::from(salt_js);
246→        assert_eq!(
247→            salt_arr.length() as usize,
248→            SALT_LEN,
249→            "salt must be SALT_LEN={} bytes",
250→            SALT_LEN
251→        );
252→
253→        // The embedded salt must match what we passed in
254→        let returned_salt = salt_arr.to_vec();
255→        assert_eq!(
256→            returned_salt,
257→            salt.to_vec(),
258→            "returned salt must match input salt"
259→        );
260→    }
261→
262→    /// `sign()` + `verify()` round-trip: a signature produced by `sign()` must
263→    /// pass `verify()` with the corresponding verifying key.
264→    #[wasm_bindgen_test]
265→    fn wasm_sign_verify_roundtrip() {
266→        let seed = [21u8; 32];
267→        let keypair = keygen(&seed).expect("keygen must succeed");
268→
269→        let sk_js = js_sys::Reflect::get(&keypair, &"sk".into()).expect("keypair must have sk");
270→        let vk_js = js_sys::Reflect::get(&keypair, &"vk".into()).expect("keypair must have vk");
271→
272→        let sk_bytes = js_sys::Uint8Array::from(sk_js).to_vec();
273→        let vk_bytes = js_sys::Uint8Array::from(vk_js).to_vec();
274→
275→        let message = b"wasm sign-verify roundtrip";
276→        let salt = [1u8; SALT_LEN];
277→
278→        let sign_result = sign(&sk_bytes, message, &salt).expect("sign must succeed with valid sk");
279→
280→        // Extract the full signature bytes
281→        let sig_js = js_sys::Reflect::get(&sign_result, &"signature".into())
282→            .expect("sign result must have signature");
283→        let sig_bytes = js_sys::Uint8Array::from(sig_js).to_vec();
284→
285→        let valid = verify(&vk_bytes, message, &sig_bytes)
286→            .expect("verify must not error on a valid signature");
287→
288→        assert!(valid, "signature produced by sign() must verify with vk");
289→    }
290→}
