  1→//! Core Falcon-512 signature scheme.
  2→
  3→use crate::common::sqnorm;
  4→use crate::encoding::{compress, decompress, deserialize_public_key, serialize_public_key};
  5→use crate::ffsampling::{ffldl_fft, ffsampling_fft, gram, normalize_tree, LdlTree};
  6→use crate::fft::{add_fft, fft, ifft, mul_fft, Complex};
  7→use crate::hash_to_point::HashToPoint;
  8→use crate::ntrugen::ntru_gen;
  9→use crate::ntt::{div_zq, mul_zq, sub_zq};
 10→use crate::rng::ChaCha20;
 11→use crate::{N, Q, SALT_LEN, SEED_LEN};
 12→use std::marker::PhantomData;
 13→
 14→/// Falcon-512 parameters.
 15→const SIGMA: f64 = 165.7366171829776;
 16→const SIGMIN: f64 = 1.2778336969128337;
 17→const SIG_BOUND: i64 = 34034726;
 18→const SIG_BYTELEN: usize = 666;
 19→const HEAD_LEN: usize = 1;
 20→const LOGN: u8 = 9; // log2(512)
 21→
 22→/// Public key byte length (512 * 14 bits / 8 = 896 bytes).
 23→pub const PUBLIC_KEY_LEN: usize = 896;
 24→
 25→/// Signature byte length (header + salt + compressed s1).
 26→pub const SIGNATURE_LEN: usize = SIG_BYTELEN;
 27→
 28→/// Error type for Falcon operations.
 29→///
 30→/// Represents the various ways Falcon cryptographic operations can fail.
 31→#[derive(Debug, Clone, PartialEq)]
 32→pub enum FalconError {
 33→    InvalidPublicKey,
 34→    InvalidSignature,
 35→    InvalidSecretKey,
 36→    SignatureNormTooLarge,
 37→    DecompressionFailed,
 38→}
 39→
 40→impl std::fmt::Display for FalconError {
 41→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 42→        match self {
 43→            FalconError::InvalidPublicKey => write!(f, "Invalid public key"),
 44→            FalconError::InvalidSignature => write!(f, "Invalid signature"),
 45→            FalconError::InvalidSecretKey => write!(f, "Invalid secret key"),
 46→            FalconError::SignatureNormTooLarge => write!(f, "Signature norm too large"),
 47→            FalconError::DecompressionFailed => write!(f, "Signature decompression failed"),
 48→        }
 49→    }
 50→}
 51→
 52→impl std::error::Error for FalconError {}
 53→
 54→/// Secret key for Falcon-512.
 55→///
 56→/// Contains the NTRU secret polynomials (f, g, F, G) and precomputed
 57→/// values for efficient signing. The secret key is used to produce
 58→/// signatures via lattice-based Gaussian sampling.
 59→///
 60→/// # Security
 61→///
 62→/// The secret key must be kept confidential. Exposure allows an attacker
 63→/// to forge signatures.
 64→pub struct SecretKey {
 65→    /// NTRU secret polynomial f.
 66→    f: [i32; N],
 67→    /// NTRU secret polynomial g.
 68→    g: [i32; N],
 69→    /// NTRU secret polynomial F.
 70→    capital_f: [i32; N],
 71→    /// NTRU secret polynomial G.
 72→    capital_g: [i32; N],
 73→    /// Basis B0 in FFT representation.
 74→    b0_fft: [[Vec<Complex>; 2]; 2],
 75→    /// LDL tree for fast sampling.
 76→    tree: LdlTree,
 77→}
 78→
 79→/// Verifying key (public key) for Falcon-512.
 80→///
 81→/// Contains the public polynomial h = g/f mod (X^n + 1, q).
 82→/// Used to verify signatures without access to the secret key.
 83→///
 84→/// # Serialization
 85→///
 86→/// The verifying key serializes to 896 bytes (512 coefficients at 14 bits each).
 87→#[derive(Clone)]
 88→pub struct VerifyingKey {
 89→    /// Public key h = g/f mod (x^n + 1, q).
 90→    h: [i32; N],
 91→}
 92→
 93→/// Signature for Falcon-512.
 94→///
 95→/// A Falcon signature consists of:
 96→/// - A header byte encoding the parameter set (log2(n))
 97→/// - A random salt (40 bytes)
 98→/// - A compressed polynomial s1
 99→///
100→/// # Serialization
101→///
102→/// The signature serializes to 666 bytes for Falcon-512.
103→pub struct Signature {
104→    /// Header byte (encodes log(n)).
105→    header: u8,
106→    /// Random salt.
107→    salt: [u8; SALT_LEN],
108→    /// Compressed signature polynomial s1.
109→    s1_enc: Vec<u8>,
110→}
111→
112→/// Compute the basis B0 in FFT representation and the LDL tree from NTRU polynomials.
113→///
114→/// This is the shared reconstruction pipeline used both during key generation
115→/// ([`Falcon::keygen_with_rng`]) and secret key deserialization ([`SecretKey::from_bytes`]).
116→/// Keeping the logic in one place prevents the two codepaths from diverging silently.
117→fn compute_signing_state(
118→    f: &[i32; N],
119→    g: &[i32; N],
120→    capital_f: &[i32; N],
121→    capital_g: &[i32; N],
122→) -> ([[Vec<Complex>; 2]; 2], LdlTree) {
123→    // Basis B0 = [[g, -f], [G, -F]] — use real negation, NOT modular negation (neg_zq)
124→    let neg_f: Vec<f64> = f.iter().map(|&x| -(x as f64)).collect();
125→    let neg_f_cap: Vec<f64> = capital_f.iter().map(|&x| -(x as f64)).collect();
126→
127→    let b0: [[Vec<f64>; 2]; 2] = [
128→        [g.iter().map(|&x| x as f64).collect(), neg_f],
129→        [capital_g.iter().map(|&x| x as f64).collect(), neg_f_cap],
130→    ];
131→
132→    let b0_fft = [
133→        [fft(&b0[0][0]), fft(&b0[0][1])],
134→        [fft(&b0[1][0]), fft(&b0[1][1])],
135→    ];
136→
137→    // Compute Gram matrix G0 = B0 * B0^* in coefficient representation
138→    let g0 = gram(&b0);
139→    let g0_fft = [
140→        [fft(&g0[0][0]), fft(&g0[0][1])],
141→        [fft(&g0[1][0]), fft(&g0[1][1])],
142→    ];
143→
144→    // Build ffLDL tree
145→    let mut tree = ffldl_fft(&g0_fft);
146→    normalize_tree(&mut tree, SIGMA);
147→
148→    (b0_fft, tree)
149→}
150→
151→impl SecretKey {
152→    /// Serialize the secret key to bytes.
153→    ///
154→    /// Format: f || g || F || G (4 polynomials, each 896 bytes).
155→    pub fn to_bytes(&self) -> Vec<u8> {
156→        let mut bytes = Vec::with_capacity(4 * PUBLIC_KEY_LEN);
157→        bytes.extend_from_slice(&serialize_public_key(&self.f));
158→        bytes.extend_from_slice(&serialize_public_key(&self.g));
159→        bytes.extend_from_slice(&serialize_public_key(&self.capital_f));
160→        bytes.extend_from_slice(&serialize_public_key(&self.capital_g));
161→        bytes
162→    }
163→
164→    /// Deserialize a secret key from bytes.
165→    ///
166→    /// Format: f || g || F || G (4 polynomials, each 896 bytes).
167→    /// Reconstructs `b0_fft` and the LDL tree required for signing.
168→    pub fn from_bytes(bytes: &[u8]) -> Result<Self, FalconError> {
169→        if bytes.len() != 4 * PUBLIC_KEY_LEN {
170→            return Err(FalconError::InvalidSecretKey);
171→        }
172→
173→        let (f_bytes, rest) = bytes.split_at(PUBLIC_KEY_LEN);
174→        let (g_bytes, rest) = rest.split_at(PUBLIC_KEY_LEN);
175→        let (capital_f_bytes, capital_g_bytes) = rest.split_at(PUBLIC_KEY_LEN);
176→
177→        let f_raw = deserialize_public_key(f_bytes).ok_or(FalconError::InvalidSecretKey)?;
178→        let g_raw = deserialize_public_key(g_bytes).ok_or(FalconError::InvalidSecretKey)?;
179→        let capital_f_raw =
180→            deserialize_public_key(capital_f_bytes).ok_or(FalconError::InvalidSecretKey)?;
181→        let capital_g_raw =
182→            deserialize_public_key(capital_g_bytes).ok_or(FalconError::InvalidSecretKey)?;
183→
184→        let half_q = Q / 2;
185→        let center = |raw: i32| if raw > half_q { raw - Q } else { raw };
186→
187→        let mut f = [0i32; N];
188→        let mut g = [0i32; N];
189→        let mut capital_f = [0i32; N];
190→        let mut capital_g = [0i32; N];
191→        for i in 0..N {
192→            f[i] = center(f_raw[i]);
193→            g[i] = center(g_raw[i]);
194→            capital_f[i] = center(capital_f_raw[i]);
195→            capital_g[i] = center(capital_g_raw[i]);
196→        }
197→
198→        let (b0_fft, tree) = compute_signing_state(&f, &g, &capital_f, &capital_g);
199→
200→        Ok(SecretKey {
201→            f,
202→            g,
203→            capital_f,
204→            capital_g,
205→            b0_fft,
206→            tree,
207→        })
208→    }
209→}
