237→impl Signature {
238→    /// Create a signature from raw components.
239→    pub fn from_components(header: u8, salt: [u8; SALT_LEN], s1_enc: Vec<u8>) -> Self {
240→        Signature {
241→            header,
242→            salt,
243→            s1_enc,
244→        }
245→    }
246→
247→    /// Serialize the signature to bytes.
248→    pub fn to_bytes(&self) -> Vec<u8> {
249→        let mut bytes = Vec::with_capacity(HEAD_LEN + SALT_LEN + self.s1_enc.len());
250→        bytes.push(self.header);
251→        bytes.extend_from_slice(&self.salt);
252→        bytes.extend_from_slice(&self.s1_enc);
253→        bytes
254→    }
255→
256→    /// Return a reference to the random salt embedded in the signature.
257→    ///
258→    /// The salt is the 40-byte random value that was generated (or provided)
259→    /// at signing time. It is also embedded in the serialized signature bytes.
260→    pub fn salt(&self) -> &[u8; SALT_LEN] {
261→        &self.salt
262→    }
263→
264→    /// Deserialize a signature from bytes.
265→    pub fn from_bytes(bytes: &[u8]) -> Result<Self, FalconError> {
266→        if bytes.len() < HEAD_LEN + SALT_LEN {
267→            return Err(FalconError::InvalidSignature);
268→        }
269→
270→        let header = bytes[0];
271→        if header != 0x30 + LOGN {
272→            return Err(FalconError::InvalidSignature);
273→        }
274→
275→        let mut salt = [0u8; SALT_LEN];
276→        salt.copy_from_slice(&bytes[HEAD_LEN..HEAD_LEN + SALT_LEN]);
277→
278→        let s1_enc = bytes[HEAD_LEN + SALT_LEN..].to_vec();
279→
280→        Ok(Signature {
281→            header,
282→            salt,
283→            s1_enc,
284→        })
285→    }
286→}
