288→/// Falcon-512 signature scheme parameterized by hash function.
289→///
290→/// The `Falcon` struct provides the core cryptographic operations:
291→/// key generation, signing, and verification.
292→///
293→/// # Type Parameter
294→///
295→/// - `H`: The hash function used to map messages to polynomials.
296→///   Use [`Shake256Hash`](crate::hash_to_point::Shake256Hash) for standard
297→///   Falcon or [`PoseidonHashToPoint`](crate::poseidon_hash::PoseidonHashToPoint) for
298→///   Starknet compatibility.
299→///
300→/// # Example
301→///
302→/// ```rust,ignore
303→/// use falcon_rs::falcon::Falcon;
304→/// use falcon_rs::hash_to_point::Shake256Hash;
305→///
306→/// let (sk, vk) = Falcon::<Shake256Hash>::keygen();
307→/// let sig = Falcon::<Shake256Hash>::sign(&sk, b"message");
308→/// assert!(Falcon::<Shake256Hash>::verify(&vk, b"message", &sig).unwrap());
309→/// ```
310→pub struct Falcon<H: HashToPoint> {
311→    _marker: PhantomData<H>,
312→}
313→
314→impl<H: HashToPoint> Falcon<H> {
315→    /// Generate a new keypair using system randomness.
316→    ///
317→    /// Creates a fresh Falcon-512 keypair using the system's cryptographically
318→    /// secure random number generator.
319→    ///
320→    /// # Returns
321→    ///
322→    /// A tuple of (secret key, verifying key).
323→    ///
324→    /// # Panics
325→    ///
326→    /// Panics if the system RNG fails to provide random bytes.
327→    #[cfg(feature = "shake")]
328→    pub fn keygen() -> (SecretKey, VerifyingKey) {
329→        use getrandom::getrandom;
330→        let mut seed = [0u8; 32];
331→        getrandom(&mut seed).expect("Failed to get random bytes");
332→        Self::keygen_with_seed(&seed)
333→    }
334→
335→    /// Generate a new keypair with a provided seed.
336→    ///
337→    /// Creates a deterministic Falcon-512 keypair from the given seed.
338→    /// The same seed will always produce the same keypair, which is
339→    /// useful for testing and key recovery.
340→    ///
341→    /// # Arguments
342→    ///
343→    /// * `seed` - A seed slice (up to 56 bytes used; shorter seeds are zero-padded)
344→    ///
345→    /// # Returns
346→    ///
347→    /// A tuple of (secret key, verifying key).
348→    pub fn keygen_with_seed(seed: &[u8]) -> (SecretKey, VerifyingKey) {
349→        // Create a deterministic RNG from the seed
350→        let mut full_seed = [0u8; SEED_LEN];
351→        let copy_len = seed.len().min(SEED_LEN);
352→        full_seed[..copy_len].copy_from_slice(&seed[..copy_len]);
353→        let mut rng = ChaCha20::new(&full_seed);
354→        let mut random_bytes = |n: usize| rng.random_bytes(n);
355→
356→        Self::keygen_with_rng(&mut random_bytes)
357→    }
358→
359→    /// Generate a new keypair with a provided random byte source.
360→    ///
361→    /// Creates a Falcon-512 keypair using a custom source of randomness.
362→    /// This is the most flexible key generation method, useful for
363→    /// deterministic testing or custom RNG implementations.
364→    ///
365→    /// # Arguments
366→    ///
367→    /// * `random_bytes` - A closure that returns `n` random bytes when called
368→    ///
369→    /// # Returns
370→    ///
371→    /// A tuple of (secret key, verifying key).
372→    pub fn keygen_with_rng<F: FnMut(usize) -> Vec<u8>>(
373→        random_bytes: &mut F,
374→    ) -> (SecretKey, VerifyingKey) {
375→        // Generate NTRU polynomials
376→        let (f, g, capital_f, capital_g) = ntru_gen(random_bytes);
377→
378→        // Compute public key h = g/f mod (x^n + 1, q)
379→        let f_vec: Vec<i32> = f.iter().copied().collect();
380→        let g_vec: Vec<i32> = g.iter().copied().collect();
381→        let h_vec = div_zq(&g_vec, &f_vec).expect("f should be invertible");
382→        let mut h = [0i32; N];
383→        h.copy_from_slice(&h_vec);
384→
385→        // Compute basis B0 and LDL tree for signing
386→        let (b0_fft, tree) = compute_signing_state(&f, &g, &capital_f, &capital_g);
387→
388→        let sk = SecretKey {
389→            f,
390→            g,
391→            capital_f,
392→            capital_g,
393→            b0_fft,
394→            tree,
395→        };
396→
397→        let vk = VerifyingKey { h };
398→
399→        (sk, vk)
400→    }
401→
402→    /// Sign a message.
403→    ///
404→    /// Creates a Falcon-512 signature over the given message using
405→    /// the secret key. A fresh random salt is generated for each signature.
406→    ///
407→    /// # Arguments
408→    ///
409→    /// * `sk` - The secret key to sign with
410→    /// * `message` - The message bytes to sign
411→    ///
412→    /// # Returns
413→    ///
414→    /// A signature that can be verified with the corresponding verifying key.
415→    ///
416→    /// # Panics
417→    ///
418→    /// Panics if the system RNG fails to provide random bytes.
419→    #[cfg(feature = "shake")]
420→    pub fn sign(sk: &SecretKey, message: &[u8]) -> Signature
421→    where
422→        H: HashToPoint<Input = u8>,
423→    {
424→        use getrandom::getrandom;
425→
426→        // Generate random salt
427→        let mut salt = [0u8; SALT_LEN];
428→        getrandom(&mut salt).expect("Failed to get random bytes");
429→
430→        Self::sign_with_salt(sk, message, &salt)
431→    }
432→
433→    /// Sign a message with a provided salt.
434→    ///
435→    /// Creates a Falcon-512 signature using a deterministic salt.
436→    /// This is useful for testing or when reproducible signatures are needed.
437→    ///
438→    /// # Arguments
439→    ///
440→    /// * `sk` - The secret key to sign with
441→    /// * `message` - The message bytes to sign
442→    /// * `salt` - A 40-byte salt value
443→    ///
444→    /// # Returns
445→    ///
446→    /// A signature that can be verified with the corresponding verifying key.
447→    ///
448→    /// # Note
449→    ///
450→    /// Using the same salt for different messages may leak information
451→    /// about the secret key. In production, prefer [`sign`](Self::sign).
452→    pub fn sign_with_salt(sk: &SecretKey, message: &[u8], salt: &[u8; SALT_LEN]) -> Signature
453→    where
454→        H: HashToPoint<Input = u8>,
455→    {
456→        let hashed = H::hash_to_point(message, salt);
457→        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
458→
459→        // Initialize seed from salt (seed persists across iterations)
460→        let mut seed = [0u8; SEED_LEN];
461→        seed[..SALT_LEN].copy_from_slice(salt);
462→
463→        // Signing loop - repeat until we find a short enough signature
464→        loop {
465→            let mut rng = ChaCha20::new(&seed);
466→            let mut random_bytes = |n: usize| rng.random_bytes(n);
467→
468→            // Sample preimage
469→            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
470→
471→            // Check Euclidean norm
472→            let s0_slice: &[i32] = &s0;
473→            let s1_slice: &[i32] = &s1;
474→            let norm = sqnorm(&[s0_slice, s1_slice]);
475→
476→            if norm <= SIG_BOUND {
477→                // Try to compress s1
478→                let slen = SIG_BYTELEN - HEAD_LEN - SALT_LEN;
479→                if let Some(s1_enc) = compress(&s1, slen) {
480→                    return Signature {
481→                        header: 0x30 + LOGN,
482→                        salt: *salt,
483→                        s1_enc,
484→                    };
485→                }
486→            }
487→
488→            // If norm too large or compression failed, try again with different randomness
489→            // Advance the seed using RNG output
490→            seed[SALT_LEN..].copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
491→        }
492→    }
493→
494→    /// Sign a pre-computed hash point, returning raw (s0, s1) polynomials.
495→    ///
496→    /// This enables signing with custom hash functions (e.g., Poseidon)
497→    /// where the hash-to-point is computed externally.
498→    ///
499→    /// # Arguments
500→    ///
501→    /// * `sk` - The secret key
502→    /// * `hash_point` - Pre-computed hash point (512 coefficients in [0, Q))
503→    /// * `seed` - 56-byte seed for the sampling PRNG
504→    ///
505→    /// # Returns
506→    ///
507→    /// `(s0, s1)` where s0 + s1*h = hash_point (mod q) and ||(s0, s1)|| is small.
508→    /// Coefficients are signed integers (centered around 0).
509→    pub fn sign_prehashed(
510→        sk: &SecretKey,
511→        hash_point: &[i16; N],
512→        seed: &[u8; SEED_LEN],
513→    ) -> (Vec<i32>, Vec<i32>) {
514→        let hashed_i32: Vec<i32> = hash_point.iter().map(|&x| x as i32).collect();
515→        let mut current_seed = *seed;
516→
517→        loop {
518→            let mut rng = ChaCha20::new(&current_seed);
519→            let mut random_bytes = |n: usize| rng.random_bytes(n);
520→
521→            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
522→
523→            let s0_slice: &[i32] = &s0;
524→            let s1_slice: &[i32] = &s1;
525→            let norm = sqnorm(&[s0_slice, s1_slice]);
526→
527→            if norm <= SIG_BOUND {
528→                return (s0, s1);
529→            }
530→
531→            // Advance seed
532→            current_seed[SALT_LEN..].copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
533→        }
534→    }
535→
536→    /// Sample a short preimage s such that s0 + s1*h = point.
537→    fn sample_preimage<F: FnMut(usize) -> Vec<u8>>(
538→        sk: &SecretKey,
539→        point: &[i32],
540→        random_bytes: &mut F,
541→    ) -> (Vec<i32>, Vec<i32>) {
542→        let [[a, b], [c, d]] = &sk.b0_fft;
543→
544→        // Compute t_fft = (point, 0) * B0^(-1)
545→        // Because the inverse of B0 has a specific form, we can optimize
546→        let point_fft = fft(&point.iter().map(|&x| x as f64).collect::<Vec<_>>());
547→        let q_f64 = Q as f64;
548→
549→        let t0_fft: Vec<Complex> = point_fft
550→            .iter()
551→            .zip(d.iter())
552→            .map(|(&p, &d_i)| {
553→                Complex::new(
554→                    p.re * d_i.re / q_f64 - p.im * d_i.im / q_f64,
555→                    p.re * d_i.im / q_f64 + p.im * d_i.re / q_f64,
556→                )
557→            })
558→            .collect();
559→
560→        let t1_fft: Vec<Complex> = point_fft
561→            .iter()
562→            .zip(b.iter())
563→            .map(|(&p, &b_i)| {
564→                let neg_p = Complex::new(-p.re, -p.im);
565→                Complex::new(
566→                    (neg_p.re * b_i.re - neg_p.im * b_i.im) / q_f64,
567→                    (neg_p.re * b_i.im + neg_p.im * b_i.re) / q_f64,
568→                )
569→            })
570→            .collect();
571→
572→        let t_fft = [t0_fft, t1_fft];
573→
574→        // Sample z using ffsampling
575→        let z_fft = ffsampling_fft(&t_fft, &sk.tree, SIGMIN, random_bytes);
576→
577→        // Compute v = z * B0
578→        let v0_fft = add_fft(&mul_fft(&z_fft[0], a), &mul_fft(&z_fft[1], c));
579→        let v1_fft = add_fft(&mul_fft(&z_fft[0], b), &mul_fft(&z_fft[1], d));
580→
581→        let v0_float = ifft(&v0_fft);
582→        let v1_float = ifft(&v1_fft);
583→
584→        let v0: Vec<i32> = v0_float.iter().map(|&x| x.round() as i32).collect();
585→        let v1: Vec<i32> = v1_float.iter().map(|&x| x.round() as i32).collect();
586→
587→        // s = (point, 0) - v
588→        // s0 = point - v0, s1 = -v1
589→        let s0: Vec<i32> = point.iter().zip(v0.iter()).map(|(&p, &v)| p - v).collect();
590→        let s1: Vec<i32> = v1.iter().map(|&v| -v).collect();
591→
592→        (s0, s1)
593→    }
594→
595→    /// Verify a signature.
596→    ///
597→    /// Checks that a signature is valid for the given message and verifying key.
598→    ///
599→    /// # Arguments
600→    ///
601→    /// * `vk` - The verifying key (public key)
602→    /// * `message` - The message that was supposedly signed
603→    /// * `sig` - The signature to verify
604→    ///
605→    /// # Returns
606→    ///
607→    /// - `Ok(true)` if the signature is valid
608→    /// - `Ok(false)` if the signature is mathematically invalid (wrong key or message)
609→    /// - `Err(FalconError)` if the signature is malformed
610→    pub fn verify(vk: &VerifyingKey, message: &[u8], sig: &Signature) -> Result<bool, FalconError>
611→    where
612→        H: HashToPoint<Input = u8>,
613→    {
614→        // Decompress s1
615→        let s1 = decompress(&sig.s1_enc, N).ok_or(FalconError::DecompressionFailed)?;
616→
617→        // Hash the message
618→        let hashed = H::hash_to_point(message, &sig.salt);
619→        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
620→
621→        // Compute s0 = hashed - s1 * h
622→        let h_vec: Vec<i32> = vk.h.iter().copied().collect();
623→        let s1_h = mul_zq(&s1, &h_vec);
624→        let s0 = sub_zq(&hashed_i32, &s1_h);
625→
626→        // Normalize s0 coefficients to (-q/2, q/2]
627→        let s0_centered: Vec<i32> = s0
628→            .iter()
629→            .map(|&c| {
630→                let c = c.rem_euclid(Q);
631→                if c > Q / 2 {
632→                    c - Q
633→                } else {
634→                    c
635→                }
636→            })
637→            .collect();
638→
639→        // Check signature norm
640→        let s0_slice: &[i32] = &s0_centered;
641→        let s1_slice: &[i32] = &s1;
642→        let norm = sqnorm(&[s0_slice, s1_slice]);
643→
644→        if norm > SIG_BOUND {
645→            return Ok(false);
646→        }
647→
648→        Ok(true)
649→    }
650→}
