652→#[cfg(all(test, feature = "shake"))]
653→mod tests {
654→    // Note: some tests below (roundtrip, wrong-length, invalid-coefficient) intentionally
655→    // overlap with the integration tests in `tests/secret_key_from_bytes_test.rs`.
656→    // The unit tests here have access to private fields (e.g. b0_fft, f/g/F/G) and verify
657→    // internal state consistency; the integration tests verify the same behaviour through
658→    // the public API only, acting as an independent regression guard.
659→    use super::*;
660→    use crate::hash_to_point::Shake256Hash;
661→
662→    /// `SecretKey::from_bytes` must reconstruct a functionally equivalent key:
663→    /// signing with the reconstructed key and verifying with the original vk must succeed.
664→    #[test]
665→    fn test_secret_key_from_bytes() {
666→        let seed = [42u8; 32];
667→        let (sk, vk) = Falcon::<Shake256Hash>::keygen_with_seed(&seed);
668→
669→        let sk_bytes = sk.to_bytes();
670→        let sk2 = SecretKey::from_bytes(&sk_bytes).expect("from_bytes must succeed for valid key");
671→
672→        let message = b"test from_bytes reconstruction";
673→        let salt = [5u8; SALT_LEN];
674→        let sig = Falcon::<Shake256Hash>::sign_with_salt(&sk2, message, &salt);
675→
676→        let result = Falcon::<Shake256Hash>::verify(&vk, message, &sig);
677→        assert!(result.is_ok(), "sign with reconstructed key must not error");
678→        assert!(
679→            result.unwrap(),
680→            "signature produced from reconstructed key must be valid"
681→        );
682→    }
