694→    /// `SecretKey::from_bytes` round-trips: signing with original and reconstructed
695→    /// keys with the same salt must produce bit-identical signatures.
696→    #[test]
697→    fn test_secret_key_from_bytes_identical_signing() {
698→        let seed = [99u8; 32];
699→        let (sk, _vk) = Falcon::<Shake256Hash>::keygen_with_seed(&seed);
700→
701→        let sk_bytes = sk.to_bytes();
702→        let sk2 = SecretKey::from_bytes(&sk_bytes).expect("round-trip must succeed");
703→
704→        let message = b"deterministic sign";
