 1→//! Hint generation for Falcon verification.
 2→//!
 3→//! Generates the mul_hint = INTT(NTT(s1) * pk_h_ntt) that allows
 4→//! Cairo to verify NTT products without computing INTT on-chain.
 5→
 6→use crate::ntt::{intt, mul_ntt, ntt};
 7→use crate::Q;
 8→
 9→/// Generate INTT(NTT(s1) * pk_h_ntt) — the mul_hint for verification.
10→pub fn generate_mul_hint(s1: &[u16], pk_h_ntt: &[u16]) -> Vec<u16> {
11→    let s1_i32: Vec<i32> = s1.iter().map(|&v| v as i32).collect();
12→    let pk_i32: Vec<i32> = pk_h_ntt.iter().map(|&v| v as i32).collect();
13→
14→    let s1_ntt = ntt(&s1_i32);
15→    let product_ntt = mul_ntt(&s1_ntt, &pk_i32);
16→    let product = intt(&product_ntt);
17→
18→    product.iter().map(|&v| v.rem_euclid(Q) as u16).collect()
19→}
20→
21→#[cfg(test)]
22→mod tests {
23→    use super::*;
24→
25→    #[test]
26→    fn test_hint_generation() {
27→        // s1 = [1, 0, 0, ...], pk_ntt = NTT([1, 0, 0, ...])
28→        let mut s1 = vec![0u16; 512];
29→        s1[0] = 1;
30→        let pk_coeff: Vec<i32> = s1.iter().map(|&v| v as i32).collect();
31→        let pk_ntt = ntt(&pk_coeff);
32→        let pk_u16: Vec<u16> = pk_ntt.iter().map(|&v| v.rem_euclid(Q) as u16).collect();
33→
34→        let hint = generate_mul_hint(&s1, &pk_u16);
35→        assert_eq!(hint.len(), 512);
36→        // hint = INTT(NTT([1,0...]) * NTT([1,0...])) = [1,0...]
37→        assert_eq!(hint[0], 1);
38→        for i in 1..512 {
39→            assert_eq!(hint[i], 0, "expected 0 at index {i}, got {}", hint[i]);
40→        }
41→    }
42→}
