  1→//! Base-Q polynomial packing for Falcon public keys.
  2→//!
  3→//! Packs 512 Zq values into 29 felt252 slots using base Q=12289 encoding:
  4→//!   felt252 = horner_pack(v0..v8) + horner_pack(v9..v17) * 2^128
  5→//!
  6→//! Matches the Cairo packing.cairo implementation exactly.
  7→
  8→use crate::poseidon_hash::Felt;
  9→use crate::Q;
 10→use lambdaworks_math::unsigned_integer::element::UnsignedInteger;
 11→
 12→const VALS_PER_U128: usize = 9;
 13→const VALS_PER_FELT: usize = 18;
 14→pub const PACKED_SLOTS: usize = 29;
 15→
 16→/// Convert a u128 to Felt
 17→fn felt_from_u128(v: u128) -> Felt {
 18→    Felt::from(&UnsignedInteger::from_u128(v))
 19→}
 20→
 21→/// 2^128 as Felt
 22→fn two_pow_128() -> Felt {
 23→    Felt::from_hex("0x100000000000000000000000000000000").unwrap()
 24→}
 25→
 26→/// Pack 512 Zq values into 29 Felt values using base-Q Horner encoding.
 27→pub fn pack_public_key(h_ntt: &[u16]) -> Vec<Felt> {
 28→    assert_eq!(h_ntt.len(), 512);
 29→    h_ntt
 30→        .chunks(VALS_PER_FELT)
 31→        .map(|chunk| {
 32→            let split = chunk.len().min(VALS_PER_U128);
 33→            let lo = horner_pack(&chunk[..split]);
 34→            let hi = if chunk.len() > split {
 35→                horner_pack(&chunk[split..])
 36→            } else {
 37→                0u128
 38→            };
 39→            felt_from_u128(lo) + felt_from_u128(hi) * two_pow_128()
 40→        })
 41→        .collect()
 42→}
 43→
 44→/// Unpack 29 Felt values back to 512 Zq values.
 45→pub fn unpack_public_key(packed: &[Felt]) -> Vec<u16> {
 46→    let mut result = Vec::with_capacity(512);
 47→    let mut remaining = 512usize;
 48→
 49→    for felt in packed {
 50→        let bytes = felt.to_bytes_be();
 51→        let high = u128::from_be_bytes(bytes[0..16].try_into().unwrap());
 52→        let low = u128::from_be_bytes(bytes[16..32].try_into().unwrap());
 53→
 54→        let lo_count = remaining.min(VALS_PER_U128);
 55→        base_q_extract(low, lo_count, &mut result);
 56→        remaining -= lo_count;
 57→
 58→        if remaining > 0 {
 59→            let hi_count = remaining.min(VALS_PER_U128);
 60→            base_q_extract(high, hi_count, &mut result);
 61→            remaining -= hi_count;
 62→        }
 63→    }
 64→    result
 65→}
 66→
 67→fn horner_pack(values: &[u16]) -> u128 {
 68→    let mut acc: u128 = 0;
 69→    for &v in values.iter().rev() {
 70→        acc = acc * Q as u128 + v as u128;
 71→    }
 72→    acc
 73→}
 74→
 75→fn base_q_extract(mut value: u128, count: usize, out: &mut Vec<u16>) {
 76→    for _ in 0..count {
 77→        out.push((value % Q as u128) as u16);
 78→        value /= Q as u128;
 79→    }
 80→}
 81→
 82→#[cfg(test)]
 83→mod tests {
 84→    use super::*;
 85→
 86→    #[test]
 87→    fn test_packing_roundtrip() {
 88→        let mut values = vec![0u16; 512];
 89→        for i in 0..512 {
 90→            values[i] = (i * 37 % 12289) as u16;
 91→        }
 92→        let packed = pack_public_key(&values);
 93→        assert_eq!(packed.len(), PACKED_SLOTS);
 94→        let unpacked = unpack_public_key(&packed);
 95→        assert_eq!(unpacked, values);
 96→    }
 97→
 98→    #[test]
 99→    fn test_packing_edge_cases() {
100→        // All zeros
101→        let zeros = vec![0u16; 512];
102→        assert_eq!(unpack_public_key(&pack_public_key(&zeros)), zeros);
103→
104→        // All max
105→        let maxes = vec![12288u16; 512];
106→        assert_eq!(unpack_public_key(&pack_public_key(&maxes)), maxes);
107→    }
108→}
