  1→//! Poseidon hash_to_point for Falcon-512 (Starknet-compatible).
  2→//!
  3→//! Uses lambdaworks PoseidonCairoStark252 to match the Cairo implementation.
  4→//! Produces 512 coefficients in [0, Q) from (message, salt) using:
  5→//! - poseidon_hash_span(message || salt) -> single felt252 seed
  6→//! - Squeeze: 22 hades_permutations, base-Q extraction (12 Zq per felt252)
  7→
  8→use crate::hash_to_point::HashToPoint;
  9→use crate::{N, Q};
 10→use lambdaworks_crypto::hash::poseidon::starknet::PoseidonCairoStark252;
 11→use lambdaworks_crypto::hash::poseidon::Poseidon;
 12→use lambdaworks_math::field::element::FieldElement;
 13→use lambdaworks_math::field::fields::fft_friendly::stark_252_prime_field::Stark252PrimeField;
 14→
 15→pub type Felt = FieldElement<Stark252PrimeField>;
 16→
 17→pub struct PoseidonHashToPoint;
 18→
 19→impl HashToPoint for PoseidonHashToPoint {
 20→    type Input = Felt;
 21→
 22→    /// Hash message and salt (as felt252 arrays) to 512 Zq coefficients.
 23→    /// This matches the Cairo PoseidonHashToPoint implementation exactly.
 24→    fn hash_to_point(message: &[Felt], salt: &[Felt]) -> [i16; N] {
 25→        // Absorb: poseidon_hash_span(message || salt) -> single felt252 seed
 26→        let combined: Vec<Felt> = message.iter().chain(salt.iter()).cloned().collect();
 27→        let seed = PoseidonCairoStark252::hash_many(&combined);
 28→
 29→        // Squeeze: 21 full rounds (504 coefficients) + 1 partial round (8 coefficients)
 30→        let mut state = [seed, Felt::zero(), Felt::zero()];
 31→        let mut coeffs = [0i16; N];
 32→        let mut idx = 0;
 33→
 34→        for _ in 0..21 {
 35→            PoseidonCairoStark252::hades_permutation(&mut state);
 36→            idx += extract_12_from_felt(&state[0], &mut coeffs, idx);
 37→            idx += extract_12_from_felt(&state[1], &mut coeffs, idx);
 38→        }
 39→
 40→        // Final round: only need 8 more from state[0]
 41→        PoseidonCairoStark252::hades_permutation(&mut state);
 42→        extract_12_from_felt(&state[0], &mut coeffs, idx);
 43→        // extract_12 stops at N=512, giving exactly 8 (6 from low + 2 from high)
 44→
 45→        coeffs
 46→    }
 47→}
 48→
 49→fn extract_12_from_felt(value: &Felt, out: &mut [i16; N], start: usize) -> usize {
 50→    let bytes = value.to_bytes_be();
 51→    // bytes is 32 bytes big-endian: [0..16] = high u128, [16..32] = low u128
 52→    let high = u128::from_be_bytes(bytes[0..16].try_into().unwrap());
 53→    let low = u128::from_be_bytes(bytes[16..32].try_into().unwrap());
 54→
 55→    let mut count = 0;
 56→    // Extract 6 from low u128 first (matching Cairo's extract_6_from_low)
 57→    count += extract_6_from_u128(low, out, start + count);
 58→    // Extract 6 from high (matching Cairo's extract_6_from_high)
 59→    count += extract_6_from_u128(high, out, start + count);
 60→    count
 61→}
 62→
 63→fn extract_6_from_u128(mut value: u128, out: &mut [i16; N], start: usize) -> usize {
 64→    for i in 0..6 {
 65→        if start + i >= N {
 66→            return i;
 67→        }
 68→        out[start + i] = (value % Q as u128) as i16;
 69→        value /= Q as u128;
 70→    }
 71→    6
 72→}
