  1→//! Integration tests for WASM bindings functionality.
  2→//!
  3→//! Tests the core operations exposed via `src/wasm.rs` — sign, hint generation,
  4→//! and public key packing — through the native Rust API. These tests validate
  5→//! correctness of the underlying logic that the wasm-bindgen wrappers delegate to.
  6→//!
  7→//! Actual wasm-bindgen browser/node tests live in `src/wasm_bindgen_tests.rs`
  8→//! and are run via `wasm-pack test --node`.
  9→
 10→#[cfg(feature = "shake")]
 11→mod wasm_sign_tests {
 12→    use falcon_rs::falcon::{Falcon, Signature, SIGNATURE_LEN};
 13→    use falcon_rs::hash_to_point::Shake256Hash;
 14→    use falcon_rs::SALT_LEN;
 15→
 16→    // ─── sign (native Rust path behind the wasm binding) ────────────────────
 17→
 18→    /// `wasm::sign` pathway: keygen → serialize sk → `SecretKey::from_bytes` →
 19→    /// `sign_with_salt` → `verify`. Validates the complete end-to-end logic that
 20→    /// `wasm::sign` delegates to, using the exact same Rust calls.
 21→    #[test]
 22→    fn test_wasm_sign_pathway_from_bytes_then_verify() {
 23→        use falcon_rs::falcon::{SecretKey, SIGNATURE_LEN};
 24→
 25→        let seed = [20u8; 32];
 26→        let (sk, vk) = Falcon::<Shake256Hash>::keygen_with_seed(&seed);
 27→
 28→        // Simulate what wasm::keygen returns (sk bytes)
 29→        let sk_bytes = sk.to_bytes();
 30→
 31→        // Simulate what wasm::sign does internally
 32→        let sk2 = SecretKey::from_bytes(&sk_bytes).expect("from_bytes must succeed");
 33→
 34→        let message = b"wasm sign pathway integration test";
 35→        let salt = [0u8; SALT_LEN];
 36→        let sig = Falcon::<Shake256Hash>::sign_with_salt(&sk2, message, &salt);
 37→
 38→        // salt() accessor must work
 39→        assert_eq!(sig.salt(), &salt, "sig.salt() must match signing salt");
 40→
 41→        // Signature length must match the constant
 42→        let sig_bytes = sig.to_bytes();
 43→        assert_eq!(
 44→            sig_bytes.len(),
 45→            SIGNATURE_LEN,
 46→            "signature length must be SIGNATURE_LEN={SIGNATURE_LEN}"
 47→        );
 48→
 49→        // Signature must verify
 50→        let result = Falcon::<Shake256Hash>::verify(&vk, message, &sig);
 51→        assert!(result.is_ok(), "verify must not error");
 52→        assert!(result.unwrap(), "signature from from_bytes key must verify");
 53→    }
 54→
 55→    /// Salt is correctly threaded through: signing with different salts produces
 56→    /// different but both-valid signatures.
 57→    #[test]
 58→    fn test_wasm_sign_pathway_salt_variety() {
 59→        use falcon_rs::falcon::SecretKey;
 60→
 61→        let seed = [22u8; 32];
 62→        let (sk, vk) = Falcon::<Shake256Hash>::keygen_with_seed(&seed);
 63→        let sk_bytes = sk.to_bytes();
 64→        let sk2 = SecretKey::from_bytes(&sk_bytes).expect("from_bytes must succeed");
 65→
 66→        let message = b"salt variety test";
 67→
 68→        let salt_a = [0xAA_u8; SALT_LEN];
 69→        let salt_b = [0xBB_u8; SALT_LEN];
 70→
 71→        let sig_a = Falcon::<Shake256Hash>::sign_with_salt(&sk2, message, &salt_a);
 72→        let sig_b = Falcon::<Shake256Hash>::sign_with_salt(&sk2, message, &salt_b);
 73→
 74→        // Different salts → different signatures
 75→        assert_ne!(
 76→            sig_a.to_bytes(),
 77→            sig_b.to_bytes(),
 78→            "different salts must produce different signatures"
 79→        );
 80→
 81→        // Both must return the correct salt via salt()
 82→        assert_eq!(sig_a.salt(), &salt_a);
 83→        assert_eq!(sig_b.salt(), &salt_b);
 84→
 85→        // Both must verify
 86→        let r_a = Falcon::<Shake256Hash>::verify(&vk, message, &sig_a);
 87→        assert!(r_a.is_ok() && r_a.unwrap(), "sig_a must verify");
 88→        let r_b = Falcon::<Shake256Hash>::verify(&vk, message, &sig_b);
 89→        assert!(r_b.is_ok() && r_b.unwrap(), "sig_b must verify");
 90→    }
 91→
 92→    /// Sign with two different seeds produces different signatures
 93→    /// (salt randomness matters).
 94→    #[test]
 95→    fn test_sign_different_salts_produce_different_signatures() {
 96→        let seed = [2u8; 32];
 97→        let (sk, _vk) = Falcon::<Shake256Hash>::keygen_with_seed(&seed);
 98→        let message = b"same message";
 99→
100→        let salt1 = [0u8; SALT_LEN];
101→        let salt2 = [1u8; SALT_LEN];
102→
103→        let sig1 = Falcon::<Shake256Hash>::sign_with_salt(&sk, message, &salt1);
104→        let sig2 = Falcon::<Shake256Hash>::sign_with_salt(&sk, message, &salt2);
105→
106→        assert_ne!(
107→            sig1.to_bytes(),
108→            sig2.to_bytes(),
109→            "different salts must produce different signatures"
110→        );
111→    }
112→
113→    /// Signature byte length matches the expected constant.
114→    #[test]
115→    fn test_signature_byte_length() {
116→        let seed = [3u8; 32];
117→        let (sk, _vk) = Falcon::<Shake256Hash>::keygen_with_seed(&seed);
118→        let salt = [0u8; SALT_LEN];
119→        let sig = Falcon::<Shake256Hash>::sign_with_salt(&sk, b"test", &salt);
120→        assert_eq!(
121→            sig.to_bytes().len(),
122→            SIGNATURE_LEN,
123→            "signature length must be SIGNATURE_LEN={SIGNATURE_LEN}"
124→        );
125→    }
126→
127→    /// `Signature::from_bytes` round-trips through serialization.
128→    #[test]
129→    fn test_signature_serialization_roundtrip() {
130→        let seed = [4u8; 32];
131→        let (sk, _vk) = Falcon::<Shake256Hash>::keygen_with_seed(&seed);
132→        let salt = [0u8; SALT_LEN];
133→        let sig = Falcon::<Shake256Hash>::sign_with_salt(&sk, b"roundtrip", &salt);
134→
135→        let bytes = sig.to_bytes();
136→        let sig2 = Signature::from_bytes(&bytes).expect("deserialization must succeed");
137→        assert_eq!(
138→            bytes,
139→            sig2.to_bytes(),
140→            "round-tripped signature bytes must match"
141→        );
142→    }
143→}
