145→// ─── hint generation ────────────────────────────────────────────────────────
146→
147→mod hint_generation_tests {
148→    use falcon_rs::hints::generate_mul_hint;
149→    use falcon_rs::ntt::ntt;
150→    use falcon_rs::Q;
151→
152→    /// Hint for identity: INTT(NTT([1,0…]) * NTT([1,0…])) == [1,0…]
153→    #[test]
154→    fn test_generate_mul_hint_identity() {
155→        let mut s1 = vec![0u16; 512];
156→        s1[0] = 1;
157→        let s1_i32: Vec<i32> = s1.iter().map(|&v| v as i32).collect();
158→        let pk_ntt_i32 = ntt(&s1_i32);
159→        let pk_ntt: Vec<u16> = pk_ntt_i32.iter().map(|&v| v.rem_euclid(Q) as u16).collect();
160→
161→        let hint = generate_mul_hint(&s1, &pk_ntt);
162→
163→        assert_eq!(hint.len(), 512);
164→        assert_eq!(hint[0], 1, "coefficient 0 of identity hint must be 1");
165→        for i in 1..512 {
166→            assert_eq!(
167→                hint[i], 0,
168→                "coefficient {i} of identity hint must be 0, got {}",
169→                hint[i]
170→            );
171→        }
172→    }
173→
174→    /// Hint length is always 512.
175→    #[test]
176→    fn test_generate_mul_hint_length() {
177→        let s1 = vec![42u16; 512];
178→        let pk_ntt = vec![1u16; 512];
179→        let hint = generate_mul_hint(&s1, &pk_ntt);
180→        assert_eq!(hint.len(), 512);
181→    }
182→
183→    /// All hint coefficients are in [0, Q).
184→    #[test]
185→    fn test_generate_mul_hint_range() {
186→        let s1: Vec<u16> = (0..512).map(|i| (i * 37 % (Q as usize)) as u16).collect();
187→        let pk_ntt: Vec<u16> = (0..512).map(|i| (i * 53 % (Q as usize)) as u16).collect();
188→        let hint = generate_mul_hint(&s1, &pk_ntt);
189→        for (i, &v) in hint.iter().enumerate() {
190→            assert!((v as i32) < Q, "hint[{i}] = {v} is not in [0, Q={Q})");
191→        }
192→    }
193→
194→    /// Zero s1 gives a zero hint (0 * anything = 0).
195→    #[test]
196→    fn test_generate_mul_hint_zero_s1() {
197→        let s1 = vec![0u16; 512];
198→        let pk_ntt: Vec<u16> = (0..512).map(|i| (i * 37 % (Q as usize)) as u16).collect();
199→        let hint = generate_mul_hint(&s1, &pk_ntt);
200→        assert!(hint.iter().all(|&v| v == 0), "zero s1 must give zero hint");
201→    }
202→
203→    /// Zero pk_ntt gives a zero hint (anything * 0 = 0).
204→    #[test]
205→    fn test_generate_mul_hint_zero_pk() {
206→        let s1: Vec<u16> = (0..512).map(|i| (i * 37 % (Q as usize)) as u16).collect();
207→        let pk_ntt = vec![0u16; 512];
208→        let hint = generate_mul_hint(&s1, &pk_ntt);
209→        assert!(
210→            hint.iter().all(|&v| v == 0),
211→            "zero pk_ntt must give zero hint"
212→        );
213→    }
214→
215→    /// Hint is consistent: calling generate_mul_hint twice with same inputs gives same result.
216→    #[test]
217→    fn test_generate_mul_hint_deterministic() {
218→        let s1: Vec<u16> = (0..512).map(|i| (i * 7 % (Q as usize)) as u16).collect();
219→        let pk_ntt: Vec<u16> = (0..512).map(|i| (i * 13 % (Q as usize)) as u16).collect();
220→        let h1 = generate_mul_hint(&s1, &pk_ntt);
221→        let h2 = generate_mul_hint(&s1, &pk_ntt);
222→        assert_eq!(h1, h2, "generate_mul_hint must be deterministic");
223→    }
224→}
