  1→/* @ts-self-types="./falcon_rs.d.ts" */
  2→
  3→/**
  4→ * Generate a new Falcon-512 keypair.
  5→ *
  6→ * Returns a JavaScript object with `sk` (secret key bytes) and `vk` (verifying key bytes).
  7→ *
  8→ * Note: Key generation is slow (~1-2 minutes) due to NTRU complexity.
  9→ * @param {Uint8Array} seed
 10→ * @returns {any}
 11→ */
 12→export function keygen(seed) {
 13→    const ptr0 = passArray8ToWasm0(seed, wasm.__wbindgen_malloc);
 14→    const len0 = WASM_VECTOR_LEN;
 15→    const ret = wasm.keygen(ptr0, len0);
 16→    if (ret[2]) {
 17→        throw takeFromExternrefTable0(ret[1]);
 18→    }
 19→    return takeFromExternrefTable0(ret[0]);
 20→}
 21→
 22→/**
 23→ * Get the public key length in bytes.
 24→ * @returns {number}
 25→ */
 26→export function public_key_length() {
 27→    const ret = wasm.public_key_length();
 28→    return ret >>> 0;
 29→}
 30→
 31→/**
 32→ * Get the salt length in bytes.
 33→ * @returns {number}
 34→ */
 35→export function salt_length() {
 36→    const ret = wasm.salt_length();
 37→    return ret >>> 0;
 38→}
 39→
 40→/**
 41→ * Sign a message with a secret key.
 42→ *
 43→ * Parameters:
 44→ * - `sk_bytes`: The secret key bytes (serialized as 4 × 896 = 3584 bytes via `SecretKey::to_bytes`)
 45→ * - `message`: The message to sign
 46→ * - `salt`: A 40-byte random salt (must be exactly `SALT_LEN` bytes)
 47→ *
 48→ * Returns a JavaScript object with:
 49→ * - `signature`: `Uint8Array` of 666 bytes (the full Falcon-512 signature)
 50→ * - `salt`: `Uint8Array` of 40 bytes (echo of the provided salt)
 51→ *
 52→ * # Notes
 53→ *
 54→ * The caller is responsible for generating a cryptographically random `salt` before
 55→ * calling this function. The same salt must not be reused for different messages.
 56→ * @param {Uint8Array} sk_bytes
 57→ * @param {Uint8Array} message
 58→ * @param {Uint8Array} salt
 59→ * @returns {any}
 60→ */
 61→export function sign(sk_bytes, message, salt) {
 62→    const ptr0 = passArray8ToWasm0(sk_bytes, wasm.__wbindgen_malloc);
 63→    const len0 = WASM_VECTOR_LEN;
 64→    const ptr1 = passArray8ToWasm0(message, wasm.__wbindgen_malloc);
 65→    const len1 = WASM_VECTOR_LEN;
 66→    const ptr2 = passArray8ToWasm0(salt, wasm.__wbindgen_malloc);
 67→    const len2 = WASM_VECTOR_LEN;
 68→    const ret = wasm.sign(ptr0, len0, ptr1, len1, ptr2, len2);
 69→    if (ret[2]) {
 70→        throw takeFromExternrefTable0(ret[1]);
 71→    }
 72→    return takeFromExternrefTable0(ret[0]);
 73→}
 74→
 75→/**
 76→ * Verify a signature.
 77→ *
 78→ * Parameters:
 79→ * - `vk_bytes`: The verifying key (public key) bytes
 80→ * - `message`: The signed message
 81→ * - `signature`: The signature bytes
 82→ *
 83→ * Returns true if the signature is valid, false otherwise.
 84→ * @param {Uint8Array} vk_bytes
 85→ * @param {Uint8Array} message
 86→ * @param {Uint8Array} signature
 87→ * @returns {boolean}
