        &result,
        &"signature".into(),
        &js_sys::Uint8Array::from(&sig.to_bytes()[..]),
    )
    .map_err(|e| JsError::new(&format!("Failed to set signature: {e:?}")))?;

    js_sys::Reflect::set(
        &result,
        &"salt".into(),
        &js_sys::Uint8Array::from(sig.salt().as_slice()),
    )
    .map_err(|e| JsError::new(&format!("Failed to set salt: {e:?}")))?;

    Ok(result.into())
}

